// Un item por screenshot, con shape explícito (evita ambigüedades del
// nodo Split Out al mezclar/renombrar campos). No arrastra 'issues' ni
// el resto del payload del scan: cada item es liviano.
const shots = $json.screenshots || [];
return shots.map((s) => ({ json: s }));

// Parseo defensivo de la respuesta de Groq (formato OpenAI-compatible):
// quita fences de markdown, intenta JSON.parse; si falla, ignora (no meter
// ruido en el reporte).
const raw = $json.choices?.[0]?.message?.content || '';
const cleaned = raw.replace(/```json/gi, '').replace(/```/g, '').trim();

let parsed = [];
try {
  parsed = JSON.parse(cleaned);
  if (!Array.isArray(parsed)) parsed = [];
} catch (e) {
  parsed = [];
}

const shot = $('Split screenshots').item.json || {};

const aiIssues = parsed.map((p) => {
  const key = `${shot.page}|ai_visual|${shot.viewport}|${(p.descripcion || p.ubicacion || '').slice(0, 60)}`;
  let h = 0;
  for (let i = 0; i < key.length; i++) h = (h * 31 + key.charCodeAt(i)) | 0;
  return {
    id: 'ai_' + (h >>> 0).toString(16),
    page: shot.page,
    viewport: shot.viewport,
    type: 'ai_visual',
    severity: (p.severidad || 'low').toLowerCase(),
    description: p.descripcion || '',
    location: p.ubicacion || '',
    source: $json.model || 'groq',
  };
});

return aiIssues.map((issue) => ({ json: { issue } }));

// Junta todos los issues de IA parseados (uno por screenshot) en un solo array
// y los reconecta con el resultado del scan determinista.
const items = $input.all();
const aiIssues = items.map((it) => it.json.issue).filter(Boolean);

const scan = $('Scan Playwright').first().json;
const config = $('Config').first().json;

return [{
  json: {
    ...scan,
    siteName: config.siteName,
    notifyUrl: config.notifyUrl,
    aiIssues,
  },
}];

// Rama sin IA: mismo shape que la rama con IA, pero aiIssues vacío.
const scan = $json;
const config = $('Config').first().json;

return [{
  json: {
    ...scan,
    siteName: config.siteName,
    notifyUrl: config.notifyUrl,
    aiIssues: [],
  },
}];

// Capa 3 — Baseline: dedup contra corridas anteriores usando el static data
// del workflow (persistencia simple para el MVP; Tarea 3 del roadmap la
// reemplaza por PostgreSQL para multi-sitio y auditoría histórica).
const item = $input.first().json;
const store = $getWorkflowStaticData('global');
store.baseline = store.baseline || {};

const siteKey = item.siteName || item.target;
const prevIds = new Set(store.baseline[siteKey] || []);

const allIssues = [...(item.issues || []), ...(item.aiIssues || [])];
const currentIds = allIssues.map((i) => i.id);

const newIssues = allIssues.filter((i) => !prevIds.has(i.id));
const resolvedIds = [...prevIds].filter((id) => !currentIds.includes(id));

store.baseline[siteKey] = currentIds;

const summary = allIssues.reduce((acc, i) => {
  acc[i.severity] = (acc[i.severity] || 0) + 1;
  return acc;
}, {});

return [{
  json: {
    target: item.target,
    siteName: siteKey,
    notifyUrl: item.notifyUrl,
    scannedAt: item.scannedAt,
    totalIssues: allIssues.length,
    newCount: newIssues.length,
    resolvedCount: resolvedIds.length,
    summary,
    newIssues,
    allIssues,
  },
}];

// Arma el mensaje de notificación (texto plano, compatible con Slack/WhatsApp).
const d = $json;
const lines = [];
lines.push(`*QA Naitus — ${d.siteName}*`);
lines.push(`Issues nuevos: ${d.newCount} (total activos: ${d.totalIssues})`);
lines.push(`Severidad: high=${d.summary.high || 0} medium=${d.summary.medium || 0} low=${d.summary.low || 0}`);
lines.push('');
for (const iss of d.newIssues.slice(0, 15)) {
  lines.push(`• [${iss.severity}] ${iss.type} — ${iss.page}${iss.viewport ? ' (' + iss.viewport + ')' : ''}`);
  if (iss.text) lines.push(`   "${iss.text}"`);
  if (iss.description) lines.push(`   ${iss.description}`);
}
if (d.newIssues.length > 15) lines.push(`… y ${d.newIssues.length - 15} más.`);

return [{ json: { message: lines.join('\n'), notifyUrl: d.notifyUrl, raw: d } }];
